import React from "react";
import { videos, Video } from "constant";

import { RowSections } from "components/layouts";

import { Link, Item, ItemWrap, Play, ItemImage, ItemTitle } from './Style'

function Videos() {
  return (
    <RowSections id='media' title='Learn more'>
      {videos.map((video: Video) => (
        <Link href={video.url}>
          <Item key={video.id}>
            <ItemWrap>
              <ItemImage src={video.thumbnail} alt={video.title} />
              <Play name='play' size='xl' />
            </ItemWrap>
            <ItemTitle>{video.title}</ItemTitle>
          </Item>
        </Link>
      ))}
    </RowSections>
  )
}

export { Videos };
