import React from "react";
import { useStaticQuery, graphql } from 'gatsby'

import {
  Container,
  Grid,
  Section,
  Title,
  TitleWrap,
  Card,
  StyledImage,
  StyledIcon
} from './Style'

function Support() {
  const data = useStaticQuery(graphql`
    query {
      snowden: file(relativePath: { eq: "images/support/snowden.webp" }) {
        childImageSharp {
          fluid(maxWidth: 180, quality: 100) {
            ...GatsbyImageSharpFluid_withWebp
          }
        }
      }
    }
  `)

  return (
    <Section id='support'>
      <Container>
        <TitleWrap>
          <Title>We have support from</Title>
        </TitleWrap>

        <Grid>
          <Card>
            <StyledImage
              fluid={data.snowden.childImageSharp.fluid}
              alt='Edward Snowden image'
            />
          </Card>
          <Card>
            <StyledIcon name='paradigm' size='fill' />
          </Card>
          <Card>
            <StyledIcon name='bankless' size='fill' />
          </Card>
          <Card>
            <StyledIcon name='juicebox' size='fill' />
          </Card>
          <Card>
            <StyledIcon name='logo' size='auto' />
          </Card>
        </Grid>
      </Container>
    </Section>
  )
}

export { Support }
